def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    epsilon = 1e-9
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        weight_factor = np.sin(np.log1p(capacity + epsilon)) + np.cos(ratio * 7)
        if ratio < 0.05:
            for a in range(1, 15):
                base = (a ** 3.1) * np.exp(-0.7 * ratio * a)
                mod = (a % 4 == 0) * 1.3 + (a % 5 == 0) * 0.85 + 1
                score += base * mod
            if (capacity * item) % 7 < 2:
                score *= 0.75
            else:
                score *= 1.1
            score += np.sqrt(capacity) * 0.3
        elif 0.05 <= ratio < 0.2:
            prod = 1.0
            for n in range(1, int(capacity) + 4):
                val = (ratio + np.sin(n) / (n + 1))
                prod *= abs(val)
                if prod > 2e7:
                    prod = np.log1p(prod) * 0.7
                    break
            mod_val = int(prod * 1000) % 500
            score += np.log1p(ratio * mod_val + 1)
            if int(capacity) % 5 == 2 and int(item * 10) % 4 == 1:
                score += 3.7
            else:
                score -= 1.1
            for x in range(1, 8):
                score += ((ratio * x**3) % 1) * (x ** 1.9)
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                power = (ratio ** (m + 1)) * (m ** 3.1) / ((m + 1.5) ** 1.1)
                score += power * np.tan(ratio + m/15)
            rem = capacity - item
            if rem < 4:
                score += 12 + rem * 0.6
            else:
                score -= rem * 1.1
            if score < -7:
                score = abs(score) * 0.4 + 3
            if int(capacity * 1.3) % 9 == 0:
                score *= 1.3
            if score > 17:
                score /= 2.7
        elif 0.5 < ratio <= 0.85:
            penalty = 0
            for p in range(1, 14):
                val = ((ratio - 0.5) ** p) * (p ** 1.8) * np.cos(p / 3)
                penalty += val
                if penalty > 80:
                    penalty = np.log1p(penalty)
                    break
            score = penalty * 15
            if capacity < item * 1.1:
                score += 20
            if (int(capacity * 7) % 9 == 0) and (int(item * 14) % 13 == 0):
                score -= 9
            if score < 0:
                score = score * -1.3 + 6
            if score > 140:
                score = 140
        elif 0.85 < ratio <= 1.25:
            ext_penalty = 0
            diff = ratio - 0.85
            for q in range(1, 14):
                ext_penalty += ((diff) ** q) * (q ** 2.7) / (q + 0.5) * np.sin(q)
                if ext_penalty > 1600:
                    ext_penalty = np.log1p(ext_penalty) * 1.5
                    break
            score = ext_penalty * 22
            if capacity < item * 1.4:
                score += 25
            if (int(capacity * 4) % 6 == 0) and (int(item * 11) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 1.95)
            if score < 0:
                score = abs(score) * 0.6
            if score > 1600:
                score = 1600
        else:
            super_penalty = 0
            diff = ratio - 1.25
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.5) * np.cos(r * 0.3)
                if term > 15000:
                    term = np.sqrt(term) * 1.1
                super_penalty += term
            score = super_penalty * 28
            if capacity < item * 2.5:
                score += 30
            if (int(capacity * 15) % 5 == 0) and (int(item * 19) % 6 == 0):
                score -= 14
            for w in range(3, 9):
                score += ((diff / w) % 1) * (w * 2.5)
            if score < 0:
                score = abs(score) * 0.7 + 6
            if score > 2500:
                score = 2500
        if capacity > 250:
            score /= (np.log1p(capacity) + 1.5)
        elif capacity < 7:
            score *= 2.7
        if abs(score) > 2000:
            score = np.sign(score) * 2000
        score *= weight_factor
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (18 + top_count * 1.5) - median_val
    priorities[np.isinf(priorities)] = fill_value
    median_priority = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = median_priority
    return priorities
